/* ─── Process raw data into full game objects ─── */

function generateLongDescription(game) {
  const t = game.title;
  const d = game.dev;
  const dl = game.dl;
  const r = game.r;
  const tags = game.tags || [];

  // Pick a varied opener based on a hash of the title for consistency
  const hash = t.split('').reduce((a, c) => a + c.charCodeAt(0), 0);

  const openerSets = {
    Action: [
      `Developed by ${d}, ${t} drops players straight into high-stakes combat where every second matters.`,
      `${t} from ${d} has earned its reputation as one of the most intense ${tags[0] || 'action'} experiences on mobile.`,
      `If you are looking for non-stop action on your phone, ${t} by ${d} is hard to beat.`,
    ],
    Puzzle: [
      `${t} by ${d} keeps things simple on the surface but hides surprising depth underneath.`,
      `Developed by ${d}, ${t} is the kind of puzzle game that starts easy and slowly takes over your free time.`,
      `${d} built ${t} around one core idea — make every level feel like a fresh challenge.`,
    ],
    Racing: [
      `${d} designed ${t} for players who want speed without the complexity of a full racing sim.`,
      `${t} from ${d} strikes a balance between accessible controls and genuine racing skill.`,
      `Whether you play for five minutes or an hour, ${t} by ${d} keeps the races feeling competitive.`,
    ],
    Sports: [
      `${d} created ${t} to capture the feel of real ${tags.includes('football') || tags.includes('soccer') ? 'football' : 'sports'} on a touchscreen.`,
      `${t} from ${d} focuses on what makes ${tags[0] || 'sports'} games fun — the competition.`,
      `With ${t}, ${d} proves that mobile sports games can feel authentic without a controller.`,
    ],
    Arcade: [
      `${t} by ${d} follows a simple formula — easy to pick up, difficult to put down.`,
      `${d} built ${t} around quick sessions that still feel rewarding after hundreds of plays.`,
      `There is a reason ${t} from ${d} has been downloaded ${dl} times — it nails the arcade feel.`,
    ],
    Casual: [
      `${d} designed ${t} for those moments when you just want to relax and play something lighthearted.`,
      `${t} from ${d} does not demand your full attention, but it earns it anyway.`,
      `What makes ${t} by ${d} work is its simplicity — no complicated tutorials, just fun.`,
    ],
    Strategy: [
      `${t} from ${d} rewards patience and planning over quick reflexes.`,
      `${d} designed ${t} for players who enjoy thinking several moves ahead.`,
      `With ${t}, ${d} proves strategy games work just as well on mobile as on PC.`,
    ],
    Adventure: [
      `${d} packed ${t} with enough content to keep you exploring for weeks.`,
      `${t} from ${d} is built around discovery — there is always something new around the next corner.`,
      `What sets ${t} apart from other ${tags[0] || 'adventure'} games is the world ${d} created.`,
    ],
  };

  const openers = openerSets[game.cat] || openerSets.Action;
  const opener = openers[hash % openers.length];

  // Build middle section based on tags
  const midParts = [];
  if (tags.includes('multiplayer') || tags.includes('battle-royale') || tags.includes('social')) {
    midParts.push(`The multiplayer component is where ${t} really shines — matching you against real opponents keeps every session unpredictable.`);
  }
  if (tags.includes('sandbox') || tags.includes('building')) {
    midParts.push(`The creative freedom on offer means no two players will have the same experience.`);
  }
  if (tags.includes('horror') || tags.includes('survival')) {
    midParts.push(`The atmosphere and tension build steadily, making each playthrough genuinely gripping.`);
  }
  if (tags.includes('runner') || tags.includes('endless')) {
    midParts.push(`Runs are quick enough for a commute but addictive enough to keep you playing at home too.`);
  }
  if (tags.includes('physics')) {
    midParts.push(`The physics engine adds a layer of unpredictability that makes even repeated levels feel fresh.`);
  }
  if (midParts.length === 0) {
    midParts.push(`The gameplay loop stays engaging because ${d} keeps adding new content through regular updates.`);
  }

  // Build closer based on price and rating
  let closer;
  if (game.price === 'Free') {
    if (r >= 4.4) {
      closer = `At ${r} stars across ${dl} downloads and no upfront cost, ${t} is an easy recommendation for anyone with a phone.`;
    } else {
      closer = `It is free to download with optional purchases, and with ${dl} installs, there is clearly a large community playing it right now.`;
    }
  } else {
    closer = `At ${game.price}, you get the full experience without ads or pay-to-win mechanics — a fair deal given the quality ${d} delivers.`;
  }

  return `${opener} ${game.short} ${midParts[0]} ${closer}`;
}

export const games = rawGames.map((g, index) => {
  const slug = g.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/-+$/, '');
  const id = String(index + 1);
  return {
    id,
    slug,
    title: g.title,
    category: g.cat,
    rating: g.r,
    score: g.r.toFixed(1),
    downloads: g.dl,
    developer: g.dev,
    age: g.age,
    version: g.ver,
    price: g.price,
    shortDescription: g.short,
    longDescription: generateLongDescription(g),
    tags: g.tags,
    featured: g.feat || false,
    trending: g.trend || false,
    // Prefer Google Play Store square icons (guaranteed 512×512
    // app icon, not marketing banner). Falls back to the original
    // Apple mzstatic CDN URL for any apkg the Play scrape didn't
    // cover. This was added because Apple's "AppIcon" URLs for
    // Free Fire / PUBG Mobile / others were marketing banners
    // (portrait/landscape art with black letterbox bars), not
    // square icons — they cropped badly in the homepage grid.
    icon: iconMap[g.apkg] || g.img,
    thumbnail: iconMap[g.apkg] || g.img,
    // Real screenshots only — if Apple's HTML scraper or the
    // audit removed an entry from screenshotMap, fall back to
    // an empty array so ScreenshotGallery cleanly hides itself
    // (it returns null on empty input). The previous fallback
    // duplicated the game icon 4× as fake gameplay screenshots
    // which looked obviously wrong on cold-traffic visits.
    screenshots: screenshotMap[g.iid] || [],
    androidUrl: g.apkg ? `https://play.google.com/store/apps/details?id=${g.apkg}` : null,
    iosUrl: g.iid ? `https://apps.apple.com/app/id${g.iid}` : null,
  };
});

/* ─── Derived data ─── */

export const categories = [...new Set(games.map((g) => g.category))];

/* ─── Helper functions ─── */

export function getGameBySlug(slug) {
  return games.find((g) => g.slug === slug) || null;
}

export function getGamesByCategory(category) {
  return games.filter((g) => g.category === category);
}

export function searchGames(query) {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  return games.filter(
    (g) =>
      g.title.toLowerCase().includes(q) ||
      g.category.toLowerCase().includes(q) ||
      g.tags.some((t) => t.toLowerCase().includes(q))
  );
}

export function getRelatedGames(game, limit = 10) {
  return games
    .filter(
      (g) =>
        g.id !== game.id &&
        (g.category === game.category || g.tags.some((t) => game.tags.includes(t)))
    )
    .slice(0, limit);
}

export function getSidebarGames(excludeId, limit = 15) {
  return games.filter((g) => g.id !== excludeId).slice(0, limit);
}

export function getFeaturedGames(limit = 10) {
  return games.filter((g) => g.featured).slice(0, limit);
}

export function getTrendingGames(limit = 10) {
  return games.filter((g) => g.trending).slice(0, limit);
}
